import React from 'react';
import '../styles/Recording.css';

function Recording() {
  return (
    <div className="recording-container">
      <h2>Recording Indicators</h2>
      <p>This page will contain the recording indicators functionality.</p>
    </div>
  );
}

export default Recording;
